powershell.exe -Command "
\$claudePath = 'C:\Users\loganf\.vscode\extensions\anthropic.claude-code-2.1.87-win32-x64\resources\native-binary'
\$currentPath = [Environment]::GetEnvironmentVariable('Path', 'User')
if (\$currentPath -like '*claude-code*') {
    Write-Host 'Already in Windows PATH'
} else {
    [Environment]::SetEnvironmentVariable('Path', \$currentPath + ';' + \$claudePath, 'User')
    Write-Host 'Added to Windows user PATH'
}
"
